export async function createOwnershipLedgerEntries(
  prisma: Prisma.TransactionClient | PrismaService,
  ownershipTransaction: OwnershipTransaction,
  context: {
    barrelId: string;
    executedBy: string;
    fromCustomerId?: string | null;
    toCustomerId?: string | null;
    ownershipPercentage: number;
    transferReasonId?: string | null;
    notes?: string | null;
  },
) {
  const normalizeCustomerId = (
    customerId?: string | null,
  ): string | null | undefined => {
    if (customerId === undefined || customerId === null) {
      return customerId;
    }

    return customerId.trim() === "" ? null : customerId;
  };

  const fromCustomerId = normalizeCustomerId(context.fromCustomerId);
  const toCustomerId = normalizeCustomerId(context.toCustomerId);

  const runInTransaction = async (tx: Prisma.TransactionClient) => {
    const barrel = await tx.barrel.findUniqueOrThrow({
      where: { id: context.barrelId },
      select: { lotId: true },
    });

    const groupTransaction = await tx.groupTransaction.create({
      data: {
        transactionType: EnumGroupTransactionType.OWNERSHIP_TRANSFER,
        status: EnumGroupTransactionStatus.COMPLETED,
        executionDate: ownershipTransaction.executedAt,
        affectedBarrelIds: [context.barrelId],
        lotId: barrel?.lotId,
        createdBy: context.executedBy,
        executedBy: context.executedBy,
        metadata: {
          ownershipTransactionId: ownershipTransaction.id,
          ownershipTransactionType: ownershipTransaction.transactionType,
          fromCustomerId: fromCustomerId,
          toCustomerId: toCustomerId,

    } as any);
  }

  return result as any;
}

