/**
 * Type guard to check if an orderBy element has a customerName property
 * Used to detect when customerName sorting is requested in nested resolvers
 * @param obj - The orderBy element to check (unknown type for safety)
 * @returns True if obj is a non-null object with a defined customerName property
 */
function hasCustomerNameSort(obj: unknown): obj is { customerName: SortOrder } {
  return (
    typeof obj === "object" &&
    obj !== null &&
    "customerName" in obj &&
    (obj as Record<string, unknown>).customerName !== undefined
  );
}

