 * @returns True if obj is a non-null object with a defined transferDate property
 */
function hasTransferDateSort(obj: unknown): obj is { transferDate: SortOrder } {
  return (
    typeof obj === "object" &&
    obj !== null &&
    "transferDate" in obj &&
    (obj as Record<string, unknown>).transferDate !== undefined
  );
}

